UPDATE plano SET descricao = REPLACE(descricao, 'WillIgreja', 'Minha Igreja Digital')
WHERE descricao LIKE '%WillIgreja%';
UPDATE plano SET descricao = REPLACE(descricao, 'WillSas', 'Minha Igreja Digital')
WHERE descricao LIKE '%WillSas%';
UPDATE plano SET descricao = REPLACE(descricao, 'Semear App', 'Minha Igreja Digital')
WHERE descricao LIKE '%Semear App%';
UPDATE plano SET nome = REPLACE(nome, 'WillIgreja', 'Minha Igreja Digital')
WHERE nome LIKE '%WillIgreja%';
UPDATE plano SET nome = REPLACE(nome, 'WillSas', 'Minha Igreja Digital')
WHERE nome LIKE '%WillSas%';
UPDATE plano SET nome = REPLACE(nome, 'Semear Completo', 'Plano Completo')
WHERE nome LIKE '%Semear Completo%';

